data.content:
Here's how to test `DataFetcher` with modern MSTest, covering success, failure, timeout, and cancellation:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;
    private readonly MockHttpMessageHandler _handler;
    private readonly DataFetcher _sut;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
        _handler = new MockHttpMessageHandler();
        _sut = new DataFetcher(new HttpClient(_handler));
    }

    [TestMethod]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        _handler.ResponseToReturn = new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.OK,
            Content = new StringContent("hello"),
        };

        var result = await _sut.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        _handler.ResponseToReturn = new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.NotFound,
        };

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await _sut.FetchAsync("https://example.com"));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_RespectsTimeout_ViaCancellationToken()
    {
        // TestContext.CancellationToken fires when [Timeout] expires,
        // so pass it through to verify cooperative cancellation.
        _handler.ResponseToReturn = new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.OK,
            Content = new StringContent("fast"),
        };

        var result = await _sut.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        Assert.AreEqual("fast", result);
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsTaskCanceledException()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await _sut.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    public async Task FetchAsync_CancelledDuringRequest_ThrowsTaskCanceledException()
    {
        using var cts = new CancellationTokenSource();

        // Handler cancels the token mid-flight
        _handler.OnSend = () => cts.Cancel();
        _handler.Delay = TimeSpan.FromMilliseconds(50);

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await _sut.FetchAsync("https://example.com", cts.Token));
    }

    // Minimal test double — no mocking framework needed
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        public HttpResponseMessage ResponseToReturn { get; set; } = new(HttpStatusCode.OK);
        public TimeSpan Delay { get; set; }
        public Action? OnSend { get; set; }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            OnSend?.Invoke();

            if (Delay > TimeSpan.Zero)
                await Task.Delay(Delay, cancellationToken);

            cancellationToken.ThrowIfCancellationRequested();
            return ResponseToReturn;
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | Why |
|---|---|
| `sealed` test class | Performance + design clarity |
| Constructor init, not `[TestInitialize]` | Enables `readonly` fields; use `[TestInitialize]` only for async setup |
| `TestContext` via constructor injection | MSTest 3.6+; gives access to `CancellationToken` |
| `[Timeout] + _testContext.CancellationToken` | Cooperative timeout — the token fires when the timeout expires |
| `Assert.ThrowsExactlyAsync<T>` | Validates the exact exception type (not `[ExpectedException]`) |
| Custom `HttpMessageHandler` | Avoids mocking `HttpClient` directly (which doesn't work well) |

The critical insight for async tests: **always pass `TestContext.CancellationToken`** to your async calls in tests with `[Timeout]`. Without it, a hung `HttpClient` call would block forever — the timeout only cancels the token, it doesn't abort the thread.
